  <div class="header">
    <h1>Trace Dataset Monitor</h1>
    <div class="header-right">
      <a href="https://chuck1823.github.io/mom-and-pop-site/" target="_blank">Mom & Pop</a>
      <span id="updated"></span>
    </div>
  </div>

  <!-- Summary card -->
  <div class="summary-card" id="summary-card">
    <div class="summary-num" id="summary-num">&mdash;</div>
    <div class="summary-label" id="summary-label">Loading...</div>
    <div class="summary-goal">Target: 200 unique labeled traces</div>
    <div class="summary-sub" id="summary-sub"></div>
  </div>

  <div id="dashboard"></div>

  <div class="refresh-note">Rebuild stats: python3 experiment/trace-dashboard/app.py → push stats.json</div>

  <script>
    async function load() {
      try { const r = await fetch('stats.json'); render(await r.json()); }
      catch(e) { document.body.innerHTML = '<p style="color:#ef5350;padding:1rem">Failed to load stats.json</p>'; }
    }

    const barColors = {
      'devops':'#4fc3f7','research':'#9c27b0','coding':'#4caf50',
      'workflow_automation':'#ff9800','general_assistant':'#888888','unclassified':'#555'
    };

    function render(data) {
      document.getElementById('updated').textContent = data.updated_at || '';
      const el = document.getElementById('dashboard');
      el.innerHTML = '';

      // Calculate combined labels across all tracks for summary
      const combinedLabels = {};
      let totalCount = 0;
      for (const trackName of ['sft', 'agentic', 'distill']) {
        const t = data.tracks[trackName];
        if (t && t.label_counts) {
          for (const [lab, ct] of Object.entries(t.label_counts)) {
            combinedLabels[lab] = (combinedLabels[lab] || 0) + ct;
          }
          totalCount += t.label_counts._total || t.total || 0;
        }
      }

      // Find leading label
      let leadingLabel = 'unclassified', leadingCount = 0;
      for (const [lab, ct] of Object.entries(combinedLabels)) {
        if (lab.startsWith('_') || lab === '_total') continue;
        if (ct > leadingCount) { leadingCount = ct; leadingLabel = lab; }
      }

      document.getElementById('summary-num').textContent = totalCount;
      document.getElementById('summary-label').textContent = leadingLabel.replace(/_/g, ' ') + ' (' + leadingCount + ')';
      const pct = Math.round(leadingCount / 200 * 100);
      document.getElementById('summary-sub').textContent = pct + '% of target';

      for (const trackName of ['sft', 'agentic', 'distill']) {
        const t = data.tracks[trackName];
        if (!t || t.total === 0) continue;

        let html = '<div class="t-card">';
        html += '<div class="t-label">' + trackName.toUpperCase() + ' — ' + t.total + ' traces</div>';
        html += '<div class="def-text">' + (data.defs[trackName]) + '</div>';

        // Quality bars
        const maxQ = Math.max(...Object.values(t.quality), 1);
        for (const [q, c] of Object.entries(t.quality)) {
          if (c === 0) continue;
          html += '<div class="q-row"><span class="q-lbl ' + q + '">' + q + '</span><div class="bar-bg"><div class="bar ' + q + '" style="width:' + (c/maxQ*100) + '%"></div></div><span class="q-ct">' + c + '</span></div>';
        }

        // Labels with goal tracking
        if (t.label_counts && Object.keys(t.label_counts).length > 1) {
          html += '<div class="l-title">Labels</div>';
          const summary = Object.entries(t.label_counts).filter(([l]) => !l.startsWith('_'));
          const maxL = Math.max(...summary.map(([l, c]) => c), 1);
          for (const [lab, ct] of summary.sort((a, b) => b[1] - a[1])) {
            const colorClass = lab;
            html += '<div class="l-row"><span class="l-name">' + lab.replace(/_/g, ' ') + '</span><div class="l-bar-bg"><div class="l-bar ' + colorClass + '" style="width:' + (ct/maxL*100) + '%"></div></div><span class="l-ct">' + ct + ' <span class="goal">/ 200</span></span></div>';
          }
        }
        html += '</div>';
        el.innerHTML += html;
      }
    }

    load();
    setInterval(load, 600000);
  </script>
</body>
